/* eslint-disable */
import { AspidaClient } from 'aspida'
import { Methods as Methods0 } from './traffic_info.json'

const api = <T>(client: AspidaClient<T>) => {
  const prefix = (client.baseURL === undefined ? 'https://i.opentidkeio.jp/data/' : client.baseURL).replace(/\/$/, '')

  return {
    traffic_info_json: {
      get: (option?: { config?: T }) =>
        client.fetch<Methods0['get']['resBody']>(prefix, '/traffic_info.json', 'GET', option).json(),
      $get: async (option?: { config?: T }) =>
        (await client.fetch<Methods0['get']['resBody']>(prefix, '/traffic_info.json', 'GET', option).json()).data
    }
  }
}

export type ApiInstance = ReturnType<typeof api>
export default api
